# 简单的映射字典
PROMPTS = {
    "polish": POLISH_PROMPT,
    "rebuttal": REBUTTAL_PROMPT,
    "idea": IDEA_PROMPT,
    "response": "你是一个通用的学术助手...", # 默认
}

def get_kimi_response(input_text: str, mode: str):
    system_content = PROMPTS.get(mode, PROMPTS["response"])

    messages = [
        {"role": "system", "content": system_content},
        {"role": "user", "content": input_text}
    ]

    try:
        completion = client.chat.completions.create(
            model="kimi-k2-turbo-preview",
            messages=messages,
            temperature=0.3,
        )
        return completion.choices[0].message.content
    except Exception as e:
        print(f"API Error: {e}")
        return "抱歉，AI 服务暂时不可用，请稍后再试。"

# --- API 路由 ---
@app.route('/api/chat', methods=['POST'])
def chat():
    data = request.json
    message = data.get('message', '')
    mode = data.get('mode', 'polish') # 默认为润色

    if not message:
        return jsonify({'error': 'Message is required'}), 400

    response_text = get_kimi_response(message, mode)

    return jsonify({
        'success': True,
        'response': response_text,
        'mode': mode
    })

if __name__ == '__main__':
    app.run(port=5000, debug=True)
